package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.Gson;
import com.google.gson.JsonIOException;
import com.google.gson.JsonSyntaxException;
import com.google.gson.reflect.TypeToken;
import com.google.gson.stream.JsonReader;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.io.IOException;
import java.io.StringReader;
import java.lang.reflect.Method;
import java.lang.reflect.Type;

class GsonFromJsonTest {

  private Gson gson;

  @BeforeEach
  void setUp() {
    gson = new Gson();
  }

  @Test
  void fromJson_withValidJsonReaderAndType_returnsExpectedObject() throws IOException {
    String json = "{\"name\":\"John\"}";
    JsonReader reader = new JsonReader(new StringReader(json));
    Type type = MyClass.class;

    MyClass result = gson.fromJson(reader, type);

    assertNotNull(result);
    assertEquals("John", result.name);
  }

  @Test
  void fromJson_withNullType_throwsNullPointerException() {
    JsonReader reader = new JsonReader(new StringReader("{}"));
    assertThrows(NullPointerException.class, () -> gson.fromJson(reader, (Type) null));
  }

  @Test
  void fromJson_withNullJsonReader_throwsNullPointerException() {
    Type type = MyClass.class;
    assertThrows(NullPointerException.class, () -> gson.fromJson((JsonReader) null, type));
  }

  @Test
  void fromJson_invokesPrivateFromJsonWithTypeToken() throws Exception {
    JsonReader mockReader = mock(JsonReader.class);
    Type mockType = String.class;

    Method fromJsonMethod = Gson.class.getDeclaredMethod("fromJson", JsonReader.class, TypeToken.class);
    fromJsonMethod.setAccessible(true);

    Object result = fromJsonMethod.invoke(gson, mockReader, TypeToken.get(mockType));
    assertNull(result); // Because Gson default fromJson with String.class returns null for empty mock
  }

  static class MyClass {
    String name;
  }
}
